from sympy import integer_log, primerange
def A025281(n):
    c, j, j2 = 0, 1, 0
    while j <= n:
        k = n//j
        m = n//k
        c += (-j2+(j2:=sum(p*integer_log(m,p)[0] for p in primerange(m+1))))*k
        j = m+1
    return c # _Chai Wah Wu_, Jun 17 2026

